const crypto = require('crypto');
const pokemon = $input.first().json;
const now = new Date();
const stamp = now.toISOString().replace(/[-:]/g, '').replace(/\.\d{3}Z$/, 'Z');
const fileName = `pokemon_${pokemon.id}_${pokemon.name}_${stamp}.json`;
const objectKey = `pokeapi/pokemon/${pokemon.id}/${fileName}`;
const payload = JSON.stringify(pokemon, null, 2);
const checksum = crypto.createHash('sha256').update(payload).digest('hex');

return [{
  json: {
    pokemon_id: pokemon.id,
    pokemon_name: pokemon.name,
    bucket_name: 'raw-pokemon',
    object_key: objectKey,
    file_name: fileName,
    file_type: 'raw_json',
    mime_type: 'application/json',
    size_bytes: Buffer.byteLength(payload),
    checksum_sha256: checksum,
    source: 'n8n:pokeapi-http',
    source_url: `https://pokeapi.co/api/v2/pokemon/${pokemon.name}`,
    status: 'success',
    workflow_run_id: $execution.id,
    metadata_json: {
      height: pokemon.height,
      weight: pokemon.weight,
      base_experience: pokemon.base_experience,
      type_count: pokemon.types?.length ?? 0
    }
  },
  binary: {
    data: await this.helpers.prepareBinaryData(Buffer.from(payload), fileName, 'application/json')
  }
}];
